const BLOG_POSTS_PER_PAGE=6;let blogCurrentPage=1;let currentCategory=null;let blogFilteredPosts=[...blogPosts];function updateFilteredPosts(){let filtered=[...blogPosts];if(currentCategory&&currentCategory!==0){filtered=filtered.filter(post=>post.catId===currentCategory)}const sortBy=document.getElementById("blog-sort")?.value||"newest";if(sortBy==="newest"){filtered=filtered.reverse()}else{filtered=[...filtered]}blogFilteredPosts=filtered}function createBlogPostCard(post){const hasImage=post.image&&post.image.trim()!=="";const imageHtml=hasImage?`<img src="${post.image}" loading="lazy" alt="${post.title}">`:'<div class="glass-placeholder"></div>';const noImageClass=hasImage?"":"no-image";return`<div class="col-xl-4 col-lg-4 col-md-6 wow fadeInUp" data-wow-delay="100ms"><div class="blog-two__single ${noImageClass}"><div class="blog-two__img">${imageHtml}<div class="blog-two__date"><span class="icon-calendar"></span><p>${post.date}</p></div></div><div class="blog-two__content"><div class="blog-two__meta-box"><ul class="blog-two__meta list-unstyled"><li><a href="${post.link}"><span class="icon-tags"></span>${post.category}</a></li><li><a href="${post.link}"><span class="icon-clock"></span>${post.readingTime}</a></li></ul></div><h4 class="blog-two__title"><a href="${post.link}">${post.title}</a></h4><p class="blog-two__text">${post.text}</p></div><div class="courses-two__content"><div class="courses-two__btn-and-client-box"><div class="courses-two__btn-box"><a href="${post.link}" class="thm-btn-two"><span>مشاهده بیشتر</span><i class="far fa-angle-double-left"></i></a></div><div class="courses-two__client-box"><div class="courses-two__client-img"><img src="${post.authorImage}" loading="lazy" alt="${post.authorName}"></div><div class="courses-two__client-content"><h4>${post.authorName}</h4><p><span class="odometer" data-count="${post.authorFollowers}">0</span><i>+</i> دنبال کننده</p></div></div></div></div></div></div>`}function updateBlogStats(){const totalPosts=blogFilteredPosts.length;const shownPosts=Math.min(BLOG_POSTS_PER_PAGE*blogCurrentPage,totalPosts);const statsEl=document.getElementById("blog-stats");if(statsEl){statsEl.innerText=`نمایش ${shownPosts} مقاله از ${totalPosts} مقاله`}}const FINAL_PAGE_LINK="#";function toggleBlogLoadMore(){const totalPosts=blogFilteredPosts.length;const totalPages=Math.ceil(totalPosts/BLOG_POSTS_PER_PAGE);const loadMoreBtn=document.getElementById('blog-load-more-btn');if(!loadMoreBtn)return;if(blogCurrentPage===totalPages&&totalPages>0){loadMoreBtn.innerHTML=`<a href="${FINAL_PAGE_LINK}" class="thm-btn-two"><span>مشاهده بیشتر مقالات</span><i class="far fa-angle-double-left"></i></a>`;loadMoreBtn.style.display='inline-flex';loadMoreBtn.removeEventListener('click',blogLoadMoreHandler);return}if(blogCurrentPage<totalPages){loadMoreBtn.innerHTML='<span>بیشتر</span><i class="far fa-angle-double-left"></i>';loadMoreBtn.style.display='inline-flex';loadMoreBtn.removeEventListener('click',blogLoadMoreHandler);loadMoreBtn.addEventListener('click',blogLoadMoreHandler)}else{loadMoreBtn.style.display='none'}}function blogLoadMoreHandler(){blogCurrentPage++;renderBlogPosts(blogCurrentPage,true)}function renderBlogPagination(){const totalPages=Math.ceil(blogFilteredPosts.length/BLOG_POSTS_PER_PAGE);const paginationUl=document.getElementById("blog-pagination");if(!paginationUl||totalPages<=1){if(paginationUl)paginationUl.innerHTML="";return}let html="";html+=`<li class="prev"><a href="#" data-page="${blogCurrentPage-1}" ${blogCurrentPage===1?'style="pointer-events:none;opacity:0.5;"':""}><i class="fas fa-arrow-right"></i></a></li>`;for(let i=1;i<=totalPages;i++){const pageStr=i<10?"0"+i:i;html+=`<li class="count ${i===blogCurrentPage?"active":""}"><a href="#" data-page="${i}">${pageStr}</a></li>`}html+=`<li class="next"><a href="#" data-page="${blogCurrentPage+1}" ${blogCurrentPage===totalPages?'style="pointer-events:none;opacity:0.5;"':""}><i class="fas fa-arrow-left"></i></a></li>`;paginationUl.innerHTML=html}function renderBlogPosts(page=blogCurrentPage,append=false){const container=document.getElementById("blog-posts-container");if(!container)return;if(blogFilteredPosts.length===0){if(!document.getElementById('loading-dots-style')){const style=document.createElement('style');style.id='loading-dots-style';style.textContent='.loading-dots span{animation:dotBlink 1.4s infinite both;font-size:2.0rem;font-weight:bold;color:#ff9437;display:inline-block;margin:0 2px}.loading-dots span:nth-child(2){animation-delay:0.2s}.loading-dots span:nth-child(3){animation-delay:0.4s}@keyframes dotBlink{0%{opacity:0.2;transform:translateY(0)}50%{opacity:1;transform:translateY(-5px)}100%{opacity:0.2;transform:translateY(0)}}';document.head.appendChild(style)}container.innerHTML=`<div class="col-12 text-center py-5"><div class="alert alert-info" style="background: #f8f9faa0; border-right: 5px solid #1976D2;"><h4 style="color: #ff6a00;">⚠️ مقاله‌ای یافت نشد</h4><p style="font-size: 1.2rem;">پستی فعلاً توسط <strong>IVAN OMGRU</strong> مدیر وب‌سایت بارگذاری نشده است.</p><p>به زودی مقالات جدیدی در این دسته منتشر خواهد شد.</p><div class="loading-dots" style="margin-top: 15px;"><span>.</span><span>.</span><span>.</span></div></div></div>`;const statsEl=document.getElementById("blog-stats");if(statsEl)statsEl.innerText=`نمایش ۰ مقاله از ۰ مقاله`;const loadMoreBtn=document.getElementById("blog-load-more-btn");if(loadMoreBtn)loadMoreBtn.style.display="none";const paginationUl=document.getElementById("blog-pagination");if(paginationUl)paginationUl.innerHTML="";return}const start=BLOG_POSTS_PER_PAGE*(page-1);const end=start+BLOG_POSTS_PER_PAGE;const postsToShow=blogFilteredPosts.slice(start,end);if(!append){container.innerHTML=""}postsToShow.forEach(post=>{container.insertAdjacentHTML("beforeend",createBlogPostCard(post))});updateBlogStats();toggleBlogLoadMore();renderBlogPagination();if(typeof WOW!=="undefined"&&!append){new WOW().init()}if(typeof Odometer!=="undefined"){document.querySelectorAll(".odometer").forEach(el=>{const count=el.getAttribute("data-count");if(count){el.innerText=count}})} }function refreshBlog(){updateFilteredPosts();blogCurrentPage=1;renderBlogPosts(1,false)}document.addEventListener("DOMContentLoaded",function(){const categoryItems=document.querySelectorAll('.main-menu__category-sub-menu li');function setActiveCategory(selectedLi){categoryItems.forEach(li=>li.classList.remove('active'));if(selectedLi)selectedLi.classList.add('active')}categoryItems.forEach(item=>{item.addEventListener('click',function(e){e.preventDefault();const catId=parseInt(this.getAttribute('data-category'));if(catId===0){currentCategory=null;setActiveCategory(this)}else{if(currentCategory===catId){currentCategory=null;setActiveCategory(null)}else{currentCategory=catId;setActiveCategory(this)}}refreshBlog()})});const blogSortSelect=document.getElementById("blog-sort");if(blogSortSelect){let lastSortValue=blogSortSelect.value;blogSortSelect.addEventListener("change",function(){if(lastSortValue!==this.value){lastSortValue=this.value;refreshBlog()}});setInterval(function(){if(blogSortSelect.value!==lastSortValue){lastSortValue=blogSortSelect.value;refreshBlog()}},300)}const blogLoadMore=document.getElementById("blog-load-more-btn");if(blogLoadMore){blogLoadMore.addEventListener("click",blogLoadMoreHandler)}const blogPagination=document.getElementById("blog-pagination");if(blogPagination){blogPagination.addEventListener("click",function(e){const link=e.target.closest("a[data-page]");if(!link)return;e.preventDefault();const page=parseInt(link.getAttribute("data-page"));const totalPages=Math.ceil(blogFilteredPosts.length/BLOG_POSTS_PER_PAGE);if(!isNaN(page)&&page>=1&&page<=totalPages){blogCurrentPage=page;renderBlogPosts(blogCurrentPage,false)}})}refreshBlog()});
